import React, { useState, useEffect } from "react";
import "./Blog.css";
import blog123 from "../assests/blog.jpeg";

const Blog = () => {
  const blogs = [
    {
      id: 1,
      title:
        "How professional and skill development training is crucial for enhancing one’s employability.",
      description:
        "Skills and knowledge are the engines of economic growth and social development of any country...",
      image: blog123,
    },
    {
      id: 2,
      title: "Human Development as a Concept.",
      description:
        "Every action we take is the result of the way we communicate to ourselves...",
      image: blog123,
    },
    {
      id: 3,
      title: "Teaching is Dead, Long Live the Teacher",
      description:
        "With 15 months of campuses being closed and online learning being pursued...",
      image: blog123,
    },
    {
      id: 4,
      title: "The Future of Learning",
      description: "How digital transformation is changing the way we learn...",
      image: blog123,
    },
    {
      id: 5,
      title: "Embracing AI in Education",
      description: "AI is transforming the education sector like never before...",
      image: blog123,
    },
    {
      id: 6,
      title: "The Role of Soft Skills",
      description:
        "Technical skills are important, but soft skills are equally valuable...",
      image: blog123,
    },
  ];

  // currentIndex represents the leftmost card currently visible
  const [currentIndex, setCurrentIndex] = useState(0);
  // visibleCount determines how many cards are visible (3 on desktop, 2 or 1 on smaller screens)
  const [visibleCount, setVisibleCount] = useState(3);

  // Update visibleCount on window resize for responsiveness
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 768) {
        setVisibleCount(1);
      } else if (window.innerWidth < 1024) {
        setVisibleCount(2);
      } else {
        setVisibleCount(3);
      }
      // Ensure currentIndex stays valid after a resize
      if (currentIndex > blogs.length - visibleCount) {
        setCurrentIndex(blogs.length - visibleCount);
      }
    };

    window.addEventListener("resize", handleResize);
    handleResize(); // Run on mount

    return () => window.removeEventListener("resize", handleResize);
  }, [currentIndex, blogs.length]);

  // Update to loop continuously
  const nextSlide = () => {
    if (currentIndex < blogs.length - visibleCount) {
      setCurrentIndex(currentIndex + 1);
    } else {
      // Wrap to start
      setCurrentIndex(0);
    }
  };

  const prevSlide = () => {
    if (currentIndex > 0) {
      setCurrentIndex(currentIndex - 1);
    } else {
      // Wrap to end
      setCurrentIndex(blogs.length - visibleCount);
    }
  };

  return (
    <section className="blog-section">
      <h2 className="blog-title">From The Blog</h2>
      <p className="blog-subtitle">
        Discover the latest insights, tips, and updates from our experts.
      </p>
      <div className="slider">
        <button className="slider-btn prev-btn" onClick={prevSlide}>
          &#10094;
        </button>
        <div className="slider-wrapper">
          <div
            className="slider-track"
            style={{
              transform: `translateX(-${(currentIndex * 100) / visibleCount}%)`,
            }}
          >
            {blogs.map((blog) => (
              <div className="blog-card" key={blog.id}>
                <img src={blog.image} alt="Blog" className="blog-image" />
                <h3 className="blog-card-title">{blog.title}</h3>
                <p className="blog-card-desc">{blog.description}</p>
              </div>
            ))}
          </div>
        </div>
        <button className="slider-btn next-btn" onClick={nextSlide}>
          &#10095;
        </button>
      </div>
    </section>
  );
};

export default Blog;
